import React from "react";
import AnimatedSection from "./AnimatedSection";

const MisionSection = () => (
  <AnimatedSection
    style={{
      display: "flex",
      alignItems: "center",
      gap: "2rem",
      flexWrap: "wrap",
    }}
  >
    <div style={{ flex: 1, minWidth: "320px" }}>
      <h2 style={{ fontWeight: "900", fontSize: "2.5rem", marginBottom: "1rem", color: "black" }}>
        IMPORTANCIA DEL LEGADO EMPRESARIAL
      </h2>
      <p style={{ fontSize: "1.3rem", lineHeight: "1.6", color: "black" }}>
        What do you do when your back’s against the wall? You get to work. Jai dropped out
        of business school, invested his tuition money, and John threw on his lab coat and
        experimented to launch our first flavor of Hydrant. And we haven't stopped since.
        Take that dehydration.
      </p>
    </div>
    <div style={{ flex: 1, minWidth: "320px" }}>
      <img
        src={require("../../assets/quien-contra-nosotros.jpg")}
        alt="Founders of Hydrant"
        style={{ width: "100%", borderRadius: "1rem", boxShadow: "0 0 15px rgba(0,0,0,0.15)" }}
      />
    </div>
  </AnimatedSection>
);

export default MisionSection;
